import{_ as t,c as r,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Licence : Clause BSL expliquée | Plannotator","description":"Découvrez les clauses de la licence Business Source License 1.1 (BSL) de Plannotator et les restrictions d'utilisation commerciale. Apprenez les scénarios autorisés, les plans de changement futurs et la date de conversion vers Apache 2.0 en 2030.","frontmatter":{"title":"Licence : Clause BSL expliquée | Plannotator","sidebarTitle":"Comprendre les règles d'utilisation commerciale","subtitle":"Licence : Clause BSL expliquée","description":"Découvrez les clauses de la licence Business Source License 1.1 (BSL) de Plannotator et les restrictions d'utilisation commerciale. Apprenez les scénarios autorisés, les plans de changement futurs et la date de conversion vers Apache 2.0 en 2030.","tags":["Licence","BSL-1.1","Utilisation commerciale"],"prerequisite":[],"order":3},"headers":[],"relativePath":"fr/backnotprop/plannotator/appendix/license/index.md","filePath":"fr/backnotprop/plannotator/appendix/license/index.md"}`),o={name:"fr/backnotprop/plannotator/appendix/license/index.md"};function a(s,e,l,c,u,p){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="explication-de-la-licence-plannotator" tabindex="-1">Explication de la licence Plannotator <a class="header-anchor" href="#explication-de-la-licence-plannotator" aria-label="Permalink to &quot;Explication de la licence Plannotator&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-avoir-termine" tabindex="-1">Ce que vous pourrez faire après avoir terminé <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-avoir-termine" aria-label="Permalink to &quot;Ce que vous pourrez faire après avoir terminé&quot;">​</a></h2><ul><li>Comprendre le type de licence et les clauses principales utilisées par Plannotator</li><li>Identifier quels scénarios d&#39;utilisation sont autorisés et lesquels sont restreints</li><li>Connaître le calendrier des futurs changements de licence</li><li>Savoir comment obtenir une licence commerciale ou contacter le titulaire</li></ul><h2 id="ce-que-vous-devez-savoir-maintenant" tabindex="-1">Ce que vous devez savoir maintenant <a class="header-anchor" href="#ce-que-vous-devez-savoir-maintenant" aria-label="Permalink to &quot;Ce que vous devez savoir maintenant&quot;">​</a></h2><p>Plannotator utilise la <strong>Business Source License 1.1 (BSL)</strong> comme sa licence open source. Il s&#39;agit d&#39;une licence spéciale conçue pour protéger la valeur commerciale tout en permettant au projet de devenir complètement open source à terme.</p><h2 id="clauses-principales" tabindex="-1">Clauses principales <a class="header-anchor" href="#clauses-principales" aria-label="Permalink to &quot;Clauses principales&quot;">​</a></h2><h3 id="type-de-licence" tabindex="-1">Type de licence <a class="header-anchor" href="#type-de-licence" aria-label="Permalink to &quot;Type de licence&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Élément</th><th>Contenu</th></tr></thead><tbody><tr><td><strong>Nom de la licence</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>Titulaire du droit d&#39;auteur</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>Projet sous licence</strong></td><td>plannotator</td></tr><tr><td><strong>Date de changement</strong></td><td>2030-01-01</td></tr><tr><td><strong>Licence après changement</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Qu&#39;est-ce que la BSL ?</p><p>La Business Source License est une licence spéciale développée par MariaDB. Elle restreint temporairement certains usages commerciaux, mais s&#39;engage à convertir le logiciel en une licence open source complète (comme Apache 2.0) à une date spécifique. Ce modèle permet aux projets open source d&#39;obtenir des revenus durables pendant le processus de commercialisation, tout en garantissant une ouverture à long terme pour la communauté.</p></div><h3 id="utilisations-autorisees" tabindex="-1">Utilisations autorisées <a class="header-anchor" href="#utilisations-autorisees" aria-label="Permalink to &quot;Utilisations autorisées&quot;">​</a></h3><p>Selon les clauses de la BSL 1.1, vous pouvez :</p><ul><li><p>✅ <strong>Copier, modifier et créer des œuvres dérivées</strong></p><ul><li>Vous pouvez effectuer un développement secondaire basé sur Plannotator</li><li>Vous pouvez modifier le code source pour l&#39;adapter à vos besoins</li></ul></li><li><p>✅ <strong>Redistribuer</strong></p><ul><li>Vous pouvez distribuer les versions originales ou modifiées</li><li>Vous devez conserver les déclarations de licence originales</li></ul></li><li><p>✅ <strong>Utilisation en environnement de non-production</strong></p><ul><li>Développement interne, tests et évaluation</li><li>Apprentissage et recherche personnelle</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Utilisation étendue par les particuliers et les entreprises</p><p>La BSL définit de manière large « l&#39;utilisation en environnement de non-production », incluant divers scénarios pour les particuliers et les entreprises. Vous et les membres de votre équipe (y compris les entrepreneurs indépendants) pouvez librement utiliser Plannotator pour le développement, les tests et le déploiement.</p></div><h3 id="restrictions-d-utilisation-important" tabindex="-1">Restrictions d&#39;utilisation (important !) <a class="header-anchor" href="#restrictions-d-utilisation-important" aria-label="Permalink to &quot;Restrictions d&#39;utilisation (important !)&quot;">​</a></h3><p><strong>Restriction principale</strong> : Il est interdit d&#39;utiliser Plannotator pour un <strong>service de planification, de contexte ou d&#39;approbation (Planning, Context, or Approval Service)</strong>.</p><h4 id="qu-est-ce-qu-un-«-service-de-planification-de-contexte-ou-d-approbation-»" tabindex="-1">Qu&#39;est-ce qu&#39;un « service de planification, de contexte ou d&#39;approbation » ? <a class="header-anchor" href="#qu-est-ce-qu-un-«-service-de-planification-de-contexte-ou-d-approbation-»" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;un « service de planification, de contexte ou d&#39;approbation » ?&quot;">​</a></h4><p>Tout produit commercial permettant à des <strong>tiers</strong> (autres que les employés et les entrepreneurs indépendants) d&#39;accéder aux fonctionnalités de Plannotator par une opération directe ou indirecte constitue un service restreint. Cela inclut notamment :</p><ul><li><p><strong>Fournisseurs de services cloud</strong></p><ul><li>Les plateformes SaaS fournissant les fonctionnalités de Plannotator comme partie de leurs services</li><li>Les fournisseurs de services hébergés fournissant Plannotator à leurs clients ou abonnés</li></ul></li><li><p><strong>Services d&#39;infrastructure</strong></p><ul><li>Fournisseurs de services de centres de données</li><li>Fournisseurs de plateformes de calcul cloud</li></ul></li><li><p><strong>Tiers fournissant des services similaires</strong></p><ul><li>Y compris tous services fournis par les entités susmentionnées et leurs sociétés affiliées</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Avertissement sur l&#39;utilisation commerciale</p><p>Si vous prévoyez d&#39;utiliser Plannotator comme partie d&#39;un service commercial pour des tiers, vous devez obtenir une licence commerciale à l&#39;avance. La violation de cette clause entraînera automatiquement la résiliation de vos droits d&#39;utilisation de toutes les versions actuelles et futures de Plannotator.</p></div><h2 id="calendrier-des-changements-de-licence" tabindex="-1">Calendrier des changements de licence <a class="header-anchor" href="#calendrier-des-changements-de-licence" aria-label="Permalink to &quot;Calendrier des changements de licence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Période</th><th>Type de licence</th><th>Description</th></tr></thead><tbody><tr><td><strong>Actuel - 2030-01-01</strong></td><td>BSL 1.1</td><td>Licence open source restreinte</td></tr><tr><td><strong>2030-01-01 et après</strong></td><td>Apache 2.0</td><td>Open source complet, sans restriction commerciale</td></tr></tbody></table><h3 id="que-se-passera-t-il-apres-le-changement" tabindex="-1">Que se passera-t-il après le changement ? <a class="header-anchor" href="#que-se-passera-t-il-apres-le-changement" aria-label="Permalink to &quot;Que se passera-t-il après le changement ?&quot;">​</a></h3><p>À partir du 1er janvier 2030, Plannotator sera automatiquement converti en <strong>Apache License 2.0</strong>. Cela signifie :</p><ul><li>✅ Toutes les restrictions commerciales seront supprimées</li><li>✅ Libre utilisation pour tout but commercial</li><li>✅ Intégration possible dans tout service SaaS</li><li>✅ Conforme aux standards des licences open source permissives</li></ul><h2 id="licence-commerciale" tabindex="-1">Licence commerciale <a class="header-anchor" href="#licence-commerciale" aria-label="Permalink to &quot;Licence commerciale&quot;">​</a></h2><p>Si vous devez utiliser Plannotator sans respecter les restrictions de la BSL (par exemple pour un service de planification, de contexte ou d&#39;approbation), vous pouvez :</p><ol><li><p><strong>Acheter une licence commerciale</strong></p><ul><li>Acheter auprès de backnotprop ou de ses distributeurs agréés</li><li>Obtenir des droits d&#39;utilisation sans restrictions de la BSL</li></ul></li><li><p><strong>Contacter le titulaire de la licence</strong></p><ul><li>Envoyer un e-mail à : backnotprop</li><li>Expliquer vos scénarios d&#39;utilisation et vos besoins</li></ul></li></ol><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><h3 id="puis-je-utiliser-plannotator-au-sein-de-mon-entreprise" tabindex="-1">Puis-je utiliser Plannotator au sein de mon entreprise ? <a class="header-anchor" href="#puis-je-utiliser-plannotator-au-sein-de-mon-entreprise" aria-label="Permalink to &quot;Puis-je utiliser Plannotator au sein de mon entreprise ?&quot;">​</a></h3><p><strong>Oui.</strong> La BSL autorise explicitement vous, vos employés et vos entrepreneurs indépendants à utiliser Plannotator pour le développement interne, les tests et le déploiement. Les restrictions ne s&#39;appliquent qu&#39;aux scénarios de fourniture de services à des <strong>tiers</strong> (non employés ni entrepreneurs).</p><h3 id="puis-je-developper-mon-propre-produit-base-sur-plannotator" tabindex="-1">Puis-je développer mon propre produit basé sur Plannotator ? <a class="header-anchor" href="#puis-je-developper-mon-propre-produit-base-sur-plannotator" aria-label="Permalink to &quot;Puis-je développer mon propre produit basé sur Plannotator ?&quot;">​</a></h3><p><strong>Oui, avec conditions.</strong> Si votre produit est :</p><ul><li>Outil interne : ✅ Autorisé</li><li>Projet personnel : ✅ Autorisé</li><li>Projet open source : ✅ Autorisé (conserver la licence BSL)</li><li>Produit commercial : ❓ Doit être évalué pour déterminer s&#39;il s&#39;agit d&#39;un « service de planification, de contexte ou d&#39;approbation »</li></ul><h3 id="mon-entreprise-est-un-fournisseur-saas-puis-je-l-utiliser" tabindex="-1">Mon entreprise est un fournisseur SaaS, puis-je l&#39;utiliser ? <a class="header-anchor" href="#mon-entreprise-est-un-fournisseur-saas-puis-je-l-utiliser" aria-label="Permalink to &quot;Mon entreprise est un fournisseur SaaS, puis-je l&#39;utiliser ?&quot;">​</a></h3><p><strong>Une licence commerciale est requise.</strong> Si votre produit SaaS fournit les fonctionnalités de Plannotator à vos clients (même en tant que fonctionnalité partielle), il s&#39;agit d&#39;un service commercial restreint et vous devez acheter une licence commerciale.</p><h3 id="apres-2030-pourrai-je-utiliser-plannotator-pour-n-importe-quel-usage" tabindex="-1">Après 2030, pourrai-je utiliser Plannotator pour n&#39;importe quel usage ? <a class="header-anchor" href="#apres-2030-pourrai-je-utiliser-plannotator-pour-n-importe-quel-usage" aria-label="Permalink to &quot;Après 2030, pourrai-je utiliser Plannotator pour n&#39;importe quel usage ?&quot;">​</a></h3><p><strong>Oui.</strong> À partir de la date de changement, Plannotator utilisera la licence Apache 2.0 et toutes les restrictions commerciales seront supprimées, vous pourrez l&#39;utiliser librement pour n&#39;importe quel usage.</p><h2 id="texte-complet-de-la-licence" tabindex="-1">Texte complet de la licence <a class="header-anchor" href="#texte-complet-de-la-licence" aria-label="Permalink to &quot;Texte complet de la licence&quot;">​</a></h2><p>Pour le texte complet de la Business Source License 1.1, veuillez vous référer au fichier <code>LICENSE</code> dans le répertoire racine du projet.</p><h2 id="coordonnees" tabindex="-1">Coordonnées <a class="header-anchor" href="#coordonnees" aria-label="Permalink to &quot;Coordonnées&quot;">​</a></h2><p>Pour obtenir une licence commerciale ou pour toute autre question, veuillez contacter :</p><ul><li><strong>Titulaire de la licence</strong> : backnotprop</li><li><strong>Dépôt du projet</strong> : <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous consultons le <strong><a href="./../../changelog/release-notes/">journal des modifications</a></strong>.</p><p>Vous verrez :</p><ul><li>L&#39;historique des versions de Plannotator</li><li>Les nouvelles fonctionnalités et améliorations de chaque version</li><li>Les corrections de bugs importantes</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer et voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Déclaration de licence</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>Texte complet de la licence</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>Informations clés</strong> :</p><ul><li>Type de licence : Business Source License 1.1 (BSL)</li><li>Titulaire du droit d&#39;auteur : backnotprop (c) 2025</li><li>Date de changement : 2030-01-01</li><li>Licence après changement : Apache License, Version 2.0</li><li>Restriction principale : Interdiction d&#39;utilisation pour les services de planification, de contexte ou d&#39;approbation</li></ul></details>',47)])])}const h=t(o,[["render",a]]);export{m as __pageData,h as default};
